import{_ as a,c as s,o,a1 as i}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Recuperação após Compressão: Habilidades se Recuperam Automaticamente | opencode-agent-skills","description":"Aprenda o mecanismo de recuperação após compressão do opencode-agent-skills. Lista de habilidades é automaticamente restaurada após compressão da sessão, usando mensagens sintéticas para manter habilidades disponíveis.","frontmatter":{"title":"Recuperação após Compressão: Habilidades se Recuperam Automaticamente | opencode-agent-skills","sidebarTitle":"Habilidades não são perdidas após compressão","subtitle":"Recuperação após Compressão: Habilidades se Recuperam Automaticamente","description":"Aprenda o mecanismo de recuperação após compressão do opencode-agent-skills. Lista de habilidades é automaticamente restaurada após compressão da sessão, usando mensagens sintéticas para manter habilidades disponíveis.","tags":["Gerenciamento de Contexto","Persistência de Sessão","Funcionalidades Avançadas"],"prerequisite":["platforms-loading-skills-into-context"],"order":4},"headers":[],"relativePath":"pt/joshuadavidthomas/opencode-agent-skills/advanced/context-compaction-resilience/index.md","filePath":"pt/joshuadavidthomas/opencode-agent-skills/advanced/context-compaction-resilience/index.md"}'),n={name:"pt/joshuadavidthomas/opencode-agent-skills/advanced/context-compaction-resilience/index.md"};function t(r,e,d,l,c,p){return o(),s("div",null,[...e[0]||(e[0]=[i(`<h1 id="mecanismo-de-recuperacao-apos-compressao-de-contexto" tabindex="-1">Mecanismo de Recuperação após Compressão de Contexto <a class="header-anchor" href="#mecanismo-de-recuperacao-apos-compressao-de-contexto" aria-label="Permalink to &quot;Mecanismo de Recuperação após Compressão de Contexto&quot;">​</a></h1><h2 id="o-que-voce-sera-capaz-de-fazer" tabindex="-1">O que você será capaz de fazer <a class="header-anchor" href="#o-que-voce-sera-capaz-de-fazer" aria-label="Permalink to &quot;O que você será capaz de fazer&quot;">​</a></h2><ul><li>Entender como o plugin mantém as habilidades disponíveis após a compressão da sessão</li><li>Saber quando a recuperação após compressão é acionada e o fluxo de execução</li><li>Ser capaz de verificar se a recuperação após compressão está funcionando corretamente</li><li>Entender o papel das mensagens sintéticas no mecanismo de recuperação</li></ul><h2 id="seu-dilema-atual" tabindex="-1">Seu dilema atual <a class="header-anchor" href="#seu-dilema-atual" aria-label="Permalink to &quot;Seu dilema atual&quot;">​</a></h2><p>Em sessões longas, o OpenCode executa <strong>Compressão de Contexto</strong> (Context Compaction) para economizar Tokens. Após a compressão, a sessão retém apenas as mensagens mais recentes, e o histórico inicial (incluindo o conteúdo das habilidades injetadas anteriormente) é removido.</p><p>Isso cria um problema: se o conteúdo das habilidades for removido pela compressão, a AI não saberá mais quais habilidades estão disponíveis e não poderá usar as habilidades carregadas.</p><h2 id="quando-usar-este-recurso" tabindex="-1">Quando usar este recurso <a class="header-anchor" href="#quando-usar-este-recurso" aria-label="Permalink to &quot;Quando usar este recurso&quot;">​</a></h2><p>O mecanismo de recuperação após compressão é <strong>executado automaticamente</strong>, não exigindo intervenção manual. No entanto, ao entender seu funcionamento, você pode solucionar problemas nos seguintes cenários:</p><ul><li>A AI &quot;esquece&quot; subitamente as habilidades em sessões longas</li><li>É necessário depurar a disponibilidade das habilidades após a compressão</li><li>Você quer entender a estratégia de gerenciamento de sessão do plugin</li></ul><h2 id="ideia-central" tabindex="-1">Ideia Central <a class="header-anchor" href="#ideia-central" aria-label="Permalink to &quot;Ideia Central&quot;">​</a></h2><h3 id="o-que-e-compressao-de-contexto" tabindex="-1">O que é compressão de contexto? <a class="header-anchor" href="#o-que-e-compressao-de-contexto" aria-label="Permalink to &quot;O que é compressão de contexto?&quot;">​</a></h3><p>As sessões do OpenCode ficam cada vez mais longas conforme as mensagens aumentam. Quando o uso de Tokens se aproxima do limite, o sistema executa automaticamente a <strong>Compressão de Contexto</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Sessão inicial] → [Mensagem 1] → [Mensagem 2] → ... → [Mensagem 50]</span></span>
<span class="line"><span>                          ↑ Ponto de compressão: retém apenas as 10 mensagens mais recentes</span></span></code></pre></div><p>Após a compressão, as mensagens iniciais (incluindo o conteúdo de injeção de habilidades) são removidas, e a AI só pode ver o histórico de mensagens mais recente.</p><h3 id="como-funciona-o-mecanismo-de-recuperacao-apos-compressao" tabindex="-1">Como funciona o mecanismo de recuperação após compressão <a class="header-anchor" href="#como-funciona-o-mecanismo-de-recuperacao-apos-compressao" aria-label="Permalink to &quot;Como funciona o mecanismo de recuperação após compressão&quot;">​</a></h3><p>O plugin monitora o evento <code>session.compacted</code> e, ao detectar a ocorrência de compressão, executa imediatamente as seguintes operações de recuperação:</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[Compressão de sessão acionada] --&gt; B[Evento session.compacted]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C{Superpowers habilitado?}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt;|Sim| D[Reinjetar prompt do Superpowers]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt;|Não| E[Pular Superpowers]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; F[Reinjetar lista de habilidades]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; G[Limpar registros de habilidades carregadas]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; H[Recuperação concluída]</span></span></code></pre></div><p><strong>Pontos principais</strong>:</p><ul><li>A recuperação é <strong>automática</strong>, não precisa ser acionada manualmente</li><li>A lista de habilidades recuperada contém <strong>todas as habilidades descobertas</strong> (não apenas as carregadas anteriormente)</li><li>Os registros de habilidades carregadas são limpos, permitindo que a AI reavalie quais habilidades são necessárias</li></ul><h3 id="o-papel-das-mensagens-sinteticas" tabindex="-1">O papel das mensagens sintéticas <a class="header-anchor" href="#o-papel-das-mensagens-sinteticas" aria-label="Permalink to &quot;O papel das mensagens sintéticas&quot;">​</a></h3><p>O plugin usa o mecanismo de <strong>Injeção de Mensagem Sintética</strong> (Synthetic Message Injection) para injetar conteúdo:</p><table tabindex="0"><thead><tr><th>Propriedade</th><th>Valor</th><th>Significado</th></tr></thead><tbody><tr><td><code>noReply</code></td><td><code>true</code></td><td>A AI não responde ao conteúdo injetado em si</td></tr><tr><td><code>synthetic</code></td><td><code>true</code></td><td>Marcado como conteúdo gerado pelo sistema, não conta como entrada do usuário, não é exibido na UI</td></tr></tbody></table><p>Isso significa que o conteúdo injetado pela recuperação após compressão:</p><ul><li>É completamente transparente para o usuário (não visível)</li><li>Não consome a cota de mensagens do usuário</li><li>Mas é lido e compreendido pela AI</li></ul><h2 id="🎒-preparacao-antes-de-comecar" tabindex="-1">🎒 Preparação antes de começar <a class="header-anchor" href="#🎒-preparacao-antes-de-comecar" aria-label="Permalink to &quot;🎒 Preparação antes de começar&quot;">​</a></h2><p>Este tutorial requer:</p><ul><li>Plugin OpenCode Agent Skills instalado</li><li>Entendimento básico de carregamento de habilidades</li><li>Uma sessão longa para testar o efeito de compressão</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Não há preparação adicional necessária; o mecanismo de recuperação após compressão é uma funcionalidade integrada do plugin.</p></div><h2 id="siga-comigo-verifique-o-efeito-da-recuperacao-apos-compressao" tabindex="-1">Siga comigo: verifique o efeito da recuperação após compressão <a class="header-anchor" href="#siga-comigo-verifique-o-efeito-da-recuperacao-apos-compressao" aria-label="Permalink to &quot;Siga comigo: verifique o efeito da recuperação após compressão&quot;">​</a></h2><h3 id="passo-1-inicie-uma-nova-sessao" tabindex="-1">Passo 1: inicie uma nova sessão <a class="header-anchor" href="#passo-1-inicie-uma-nova-sessao" aria-label="Permalink to &quot;Passo 1: inicie uma nova sessão&quot;">​</a></h3><p><strong>Por que</strong> Verifique se a lista de habilidades é injetada corretamente na inicialização da sessão</p><p>Inicie uma nova sessão, digite qualquer mensagem:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Olá</span></span></code></pre></div><p><strong>Você deve ver</strong>: A AI responde normalmente e, em segundo plano, injeta automaticamente a lista de habilidades (invisível para o usuário)</p><h3 id="passo-2-carregue-uma-habilidade" tabindex="-1">Passo 2: carregue uma habilidade <a class="header-anchor" href="#passo-2-carregue-uma-habilidade" aria-label="Permalink to &quot;Passo 2: carregue uma habilidade&quot;">​</a></h3><p><strong>Por que</strong> Garanta que o conteúdo da habilidade seja injetado no contexto</p><p>Chame a ferramenta <code>use_skill</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Use get_available_skills para ver as habilidades disponíveis, depois use use_skill para carregar uma das habilidades</span></span></code></pre></div><p><strong>Você deve ver</strong>: A AI lista as habilidades disponíveis e depois carrega a habilidade que você escolheu</p><h3 id="passo-3-acione-a-compressao-de-contexto" tabindex="-1">Passo 3: acione a compressão de contexto <a class="header-anchor" href="#passo-3-acione-a-compressao-de-contexto" aria-label="Permalink to &quot;Passo 3: acione a compressão de contexto&quot;">​</a></h3><p><strong>Por que</strong> Simule um cenário de sessão longa, acionando o mecanismo de compressão do OpenCode</p><p>Continue enviando mensagens para simular uma conversa longa:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Mensagem 1: conteúdo de teste</span></span>
<span class="line"><span>Mensagem 2: continuando o teste</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>(Repita enviando 20-30 mensagens)</span></span></code></pre></div><p><strong>Você deve ver</strong>:</p><ul><li>Conforme as mensagens aumentam, o histórico da sessão fica mais longo</li><li>Após atingir um certo comprimento, o OpenCode executa automaticamente a compressão</li><li>Após a compressão, as mensagens iniciais (incluindo a injeção de habilidades) são removidas</li></ul><h3 id="passo-4-verifique-o-efeito-da-recuperacao" tabindex="-1">Passo 4: verifique o efeito da recuperação <a class="header-anchor" href="#passo-4-verifique-o-efeito-da-recuperacao" aria-label="Permalink to &quot;Passo 4: verifique o efeito da recuperação&quot;">​</a></h3><p><strong>Por que</strong> Verifique se a lista de habilidades foi reinjetada após a compressão</p><p>Após a compressão, peça à AI para usar uma habilidade novamente:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Ajude-me a usar a habilidade git-helper para criar uma nova ramificação (assumindo que você já instalou a habilidade git-helper)</span></span></code></pre></div><p><strong>Você deve ver</strong>:</p><ul><li>A AI ainda sabe quais habilidades estão disponíveis (prova de que a lista de habilidades foi restaurada)</li><li>A AI pode carregar e usar habilidades normalmente (prova de que a funcionalidade das habilidades não foi afetada pela compressão)</li></ul><h3 id="passo-5-verifique-a-injecao-de-mensagens-sinteticas" tabindex="-1">Passo 5: verifique a injeção de mensagens sintéticas <a class="header-anchor" href="#passo-5-verifique-a-injecao-de-mensagens-sinteticas" aria-label="Permalink to &quot;Passo 5: verifique a injeção de mensagens sintéticas&quot;">​</a></h3><p><strong>Por que</strong> Confirme que o mecanismo de recuperação usa mensagens sintéticas, não interferindo na conversa</p><p>Se o plugin suportar, você pode verificar o histórico de mensagens da sessão (dependendo da funcionalidade do OpenCode):</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Use ferramentas de depuração para ver o histórico de mensagens da sessão</span></span></code></pre></div><p><strong>Você deve ver</strong>:</p><ul><li>A mensagem de lista de habilidades recuperada é marcada como <code>synthetic: true</code></li><li>Estas mensagens não são exibidas na interface de conversa normal</li></ul><h2 id="ponto-de-verificacao-✅" tabindex="-1">Ponto de verificação ✅ <a class="header-anchor" href="#ponto-de-verificacao-✅" aria-label="Permalink to &quot;Ponto de verificação ✅&quot;">​</a></h2><p>Após concluir as etapas acima, você deve ser capaz de confirmar:</p><ul><li>[ ] A AI ainda pode acessar a lista de habilidades em sessões longas</li><li>[ ] A funcionalidade de carregamento de habilidades funciona normalmente após a compressão</li><li>[ ] O processo de recuperação é completamente transparente para o usuário</li></ul><h2 id="avisos-sobre-armadilhas" tabindex="-1">Avisos sobre armadilhas <a class="header-anchor" href="#avisos-sobre-armadilhas" aria-label="Permalink to &quot;Avisos sobre armadilhas&quot;">​</a></h2><h3 id="problema-1-apos-a-compressao-a-ai-diz-habilidade-nao-encontrada" tabindex="-1">Problema 1: após a compressão, a AI diz &quot;habilidade não encontrada&quot; <a class="header-anchor" href="#problema-1-apos-a-compressao-a-ai-diz-habilidade-nao-encontrada" aria-label="Permalink to &quot;Problema 1: após a compressão, a AI diz &quot;habilidade não encontrada&quot;&quot;">​</a></h3><p><strong>Possíveis causas</strong>:</p><ul><li>O plugin não está monitorando corretamente o evento <code>session.compacted</code></li><li>O caminho do diretório de habilidades mudou</li></ul><p><strong>Solução</strong>:</p><ol><li><p><strong>Verifique se o evento de compressão foi acionado</strong></p><ul><li>Através dos passos 3 e 4 de &quot;Siga comigo&quot;, confirme que após a compressão a AI ainda pode acessar a lista de habilidades</li><li>Se a AI pode usar habilidades normalmente, o mecanismo de recuperação após compressão está funcionando</li></ul></li><li><p><strong>Verifique se o plugin foi carregado corretamente</strong></p><ul><li>Reinicie o OpenCode</li><li>Após iniciar uma nova sessão, peça à AI para listar as habilidades disponíveis (<code>get_available_skills</code>)</li><li>Se você pode ver a lista de habilidades, o plugin foi carregado corretamente</li></ul></li></ol><h3 id="problema-2-a-lista-de-habilidades-recuperada-esta-vazia" tabindex="-1">Problema 2: a lista de habilidades recuperada está vazia <a class="header-anchor" href="#problema-2-a-lista-de-habilidades-recuperada-esta-vazia" aria-label="Permalink to &quot;Problema 2: a lista de habilidades recuperada está vazia&quot;">​</a></h3><p><strong>Possíveis causas</strong>:</p><ul><li>Não há habilidades no caminho de descoberta</li><li>Formato de arquivo de habilidade incorreto</li></ul><p><strong>Solução</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Consultar manualmente as habilidades disponíveis</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Use</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get_available_skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> para</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ver</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> lista</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> de</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> habilidades</span></span></code></pre></div><p>Se retornar uma lista vazia, verifique o diretório de habilidades e o formato do arquivo.</p><h3 id="problema-3-apos-a-compressao-o-estado-das-habilidades-carregadas-e-perdido" tabindex="-1">Problema 3: após a compressão, o estado das habilidades carregadas é perdido <a class="header-anchor" href="#problema-3-apos-a-compressao-o-estado-das-habilidades-carregadas-e-perdido" aria-label="Permalink to &quot;Problema 3: após a compressão, o estado das habilidades carregadas é perdido&quot;">​</a></h3><p><strong>Este é um comportamento esperado</strong>, não um Bug. O mecanismo de recuperação limpa o registro <code>loadedSkillsPerSession</code>, permitindo que a AI reavalie quais habilidades são necessárias.</p><p><strong>Solução</strong>: A AI decidirá automaticamente se deve recarregar habilidades com base no contexto, sem necessidade de intervenção manual.</p><h2 id="resumo-desta-licao" tabindex="-1">Resumo desta lição <a class="header-anchor" href="#resumo-desta-licao" aria-label="Permalink to &quot;Resumo desta lição&quot;">​</a></h2><p>O mecanismo de recuperação após compressão garante a disponibilidade de habilidades em sessões longas através das seguintes maneiras:</p><ol><li><strong>Monitorar eventos de compressão</strong>: detecta automaticamente o evento <code>session.compacted</code></li><li><strong>Reinjetar lista de habilidades</strong>: usa a tag <code>&lt;available-skills&gt;</code> para injetar todas as habilidades</li><li><strong>Recuperação opcional do Superpowers</strong>: se habilitado, restaura simultaneamente o prompt do Superpowers</li><li><strong>Usar mensagens sintéticas</strong>: o processo de recuperação é transparente para o usuário, não afeta a conversa</li><li><strong>Redefinir registros carregados</strong>: limpa o conjunto de habilidades carregadas, permitindo reavaliação</li></ol><p>Este mecanismo garante que:</p><ul><li>Habilidades sempre estejam disponíveis em sessões longas</li><li>O processo de recuperação seja automatizado e imperceptível</li><li>A AI possa decidir quais habilidades usar com base no contexto mais recente</li></ul><h2 id="proximo-preview-da-proxima-licao" tabindex="-1">Próximo preview da próxima lição <a class="header-anchor" href="#proximo-preview-da-proxima-licao" aria-label="Permalink to &quot;Próximo preview da próxima lição&quot;">​</a></h2><blockquote><p>Na próxima lição, aprenderemos <strong><a href="./../../faq/troubleshooting/">Solução de problemas</a></strong>.</p><p>Você aprenderá:</p><ul><li>Como lidar com erros comuns e exceções</li><li>Técnicas de solução de problemas relacionadas à recuperação após compressão</li><li>Soluções para outros problemas de uso</li></ul></blockquote><hr><h2 id="apendice-referencia-do-codigo-fonte" tabindex="-1">Apêndice: Referência do código fonte <a class="header-anchor" href="#apendice-referencia-do-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referência do código fonte&quot;">​</a></h2><details><summary><strong>Clique para expandir e ver a localização do código fonte</strong></summary><blockquote><p>Última atualização: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidade</th><th>Caminho do arquivo</th><th>Número de linha</th></tr></thead><tbody><tr><td>Monitoramento de evento de compressão</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L144-L157" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>144-157</td></tr><tr><td>Inicialização da primeira mensagem</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L70-L105" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>70-105</td></tr><tr><td>Injeção de lista de habilidades</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L345-L370" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>345-370</td></tr><tr><td>Injeção de mensagem sintética</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/utils.ts#L147-L162" target="_blank" rel="noreferrer"><code>src/utils.ts</code></a></td><td>147-162</td></tr><tr><td>Gerenciamento de estado da sessão</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L25-L35" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>25-35</td></tr></tbody></table><p><strong>Variáveis principais</strong>:</p><ul><li><code>setupCompleteSessions: Set&lt;string&gt;</code>: registra IDs de sessão que completaram a inicialização</li><li><code>loadedSkillsPerSession: Map&lt;string, Set&lt;string&gt;&gt;</code>: registra nomes de habilidades carregadas em cada sessão</li></ul><p><strong>Funções principais</strong>:</p><ul><li><code>injectSkillsList()</code>: injeta lista de habilidades disponíveis na sessão</li><li><code>injectSyntheticContent()</code>: injeta conteúdo usando mensagens sintéticas</li><li><code>getSessionContext()</code>: obtém informações de model e agent da sessão</li></ul></details>`,85)])])}const h=a(n,[["render",t]]);export{u as __pageData,h as default};
